&lt;li style=&quot;font-family: helvetica, arial, sans-serif; font-size: 10pt;&quot;&gt;&lt;span style=&quot;font-family: helvetica, arial, sans-serif; font-size: 10pt;&quot;&gt;Database and/or Postgres specific&lt;/span&gt;&lt;/li&gt;
